class Solution:
    def distance(self, nums):
        n = len(nums)
        arr = [0] * n
        for i in range(n):
            total = 0
            for j in range(n):
                if j != i and nums[j] == nums[i]:
                    total += abs(i - j)
            arr[i] = total
        return arr

