var distance = function(nums) {
    const n = nums.length;
    const groups = new Map();
    for (let i = 0; i < n; i++) {
        if (!groups.has(nums[i])) groups.set(nums[i], []);
        groups.get(nums[i]).push(i);
    }
    const arr = new Array(n).fill(0);
    for (const idxs of groups.values()) {
        const m = idxs.length;
        const prefix = new Array(m + 1).fill(0);
        for (let i = 0; i < m; i++) prefix[i + 1] = prefix[i] + idxs[i];
        const totalSum = prefix[m];
        for (let t = 0; t < m; t++) {
            const idx = idxs[t];
            const leftCount = t;
            const leftSum = prefix[t];
            const rightCount = m - t - 1;
            const rightSum = totalSum - prefix[t + 1];
            arr[idx] = (idx * leftCount - leftSum) + (rightSum - idx * rightCount);
        }
    }
    return arr;
};
